"""
MKT Original Commentary — Nehemiah chapters 1–4
Run: python3 scripts/zc-original-nehemiah-1-4.py
Verses: ch1×11 + ch2×20 + ch3×32 + ch4×23 = 86
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIG = {
  "1": {
    "1": "<p><em>diḇrê nᵉḥemyāh ben-ḥaḵalyāh</em>: 'the words of Nehemiah son of Hacaliah.' <em>Nᵉḥemyāh</em> means 'YHWH has comforted' (from <em>nāḥam</em>, to comfort), a theologically resonant name given his role in restoring the exilic community. The memoir opens with a date: the month <em>kislew</em> (November–December) in the twentieth year of Artaxerxes I, placing the scene in 445 BCE. The location is <em>haššûšān habîrāh</em>, 'Susa the citadel' — <em>bîrāh</em> is an Aramaic loanword (cf. Ezra 6:2; Dan 8:2) meaning fortified palace or citadel, reflecting the heavy Aramaic influence on official Persian-period vocabulary. Susa was one of the four Achaemenid capitals (Pasargadae, Ecbatana, Persepolis, Susa); it served as the administrative center where Nehemiah held his court position.</p>",
    "2": "<p><em>wayyāḇôʾ ḥanānî ʾeḥāḏ mēʾaḥay hûʾ waʾanāšîm mîyhûḏāh</em>: 'and Hanani, one of my brothers, came, he and certain men from Judah.' The word <em>ʾāḥ</em> can mean biological brother or a fellow Israelite; Neh 7:2 identifies Hanani as placed over Jerusalem, suggesting a close family relationship. The visitors brought news of conditions in Jerusalem. The phrase <em>hayyᵉhûḏîm happālêṭāh</em>, 'the Jews, the survivors,' uses <em>pālêṭāh</em> (escaped remnant) — the same term used for those who survived the destruction; it frames the post-exilic community as a remnant rather than a full restoration, maintaining the eschatological tension of the period.</p>",
    "3": "<p><em>hammûr ḥārāʿāh gᵉḏôlāh ûḥerpāh</em>: 'in great trouble and shame.' The two terms define the community's condition: <em>rāʿāh</em> is general calamity or evil, and <em>ḥerpāh</em> is the specific shame-word — reproach, disgrace, the social humiliation of a people who have failed to reconstitute their defenses. The walls of Jerusalem were broken (<em>pᵉrûṣāh</em>, the same root used of breaches) and the gates burned with fire. The physical desolation is also covenantal: a city without walls is a city without honor, without standing before other nations, a living embodiment of the curse of Deuteronomy 28.</p>",
    "4": "<p><em>wāʾeḇkeh wāʾetʾabbᵉlāh yāmîm</em>: 'and I wept and mourned for days.' The sequence — weeping, mourning, fasting, and praying — follows the classic lament pattern of the post-exilic community (cf. Dan 9:3; Ezra 9:3-5). <em>ʾāḇal</em> (to mourn) is the formal mourning posture, not mere sadness. Nehemiah's fasting and prayer before the God of heaven (<em>ʾĕlōhê haššāmayim</em>) is the typical Achaemenid-period designation used in official contexts with non-Israelites (cf. Ezra 1:2; Gen 24:3) — it is the ecumenically intelligible name for YHWH in a Persian world.</p>",
    "5": "<p><em>ʾānnāʾ YHWH ʾĕlōhê haššāmayim hāʾēl haggāḏôl wᵉhannôrāʾ šōmēr habᵉrît wāḥeseḏ</em>: 'Please, YHWH God of heaven, the great and awesome God who keeps covenant and steadfast love.' This prayer address is virtually identical to Daniel's prayer in Dan 9:4, both drawing on Deuteronomy's covenant formulary (Deut 7:9, 21). The combination of <em>gāḏôl wᵉnôrāʾ</em> (great and awesome) is the Deuteronomic description of YHWH's character (Deut 10:17); <em>šōmēr habᵉrît wāḥeseḏ</em> (keeping covenant and steadfast love) is the basis for all petition. The prayer's authority rests entirely on what YHWH has already committed to in the covenant — Nehemiah is not making a new appeal but calling in an existing obligation.</p>",
    "6": "<p><em>tᵉhî nāʾ ʾoznᵉḵā qaššeḇet wᵉʿêneḵā pᵉtuḥôt lišmōaʿ</em>: 'let your ear be attentive and your eyes open.' The two anatomical metaphors — ear attentive (<em>qaššeḇet</em>) and eyes open — frame YHWH as a king who can choose to notice or ignore. The prayer is a plea for divine attention. <em>mōḏeh ʾanî ʿal-ḥaṭṭōʾt bᵉnê yiśrāʾēl</em>: 'I confess the sins of the people of Israel' — Nehemiah identifies himself with the community's sin using <em>yāḏāh</em> in the hithpael (confess, acknowledge), the same root used in psalms of lament and corporate confession. The 'we' of confession includes Nehemiah's own household: <em>ûḇêt-ʾāḇî ḥāṭāʾnû</em>, 'I and my father's house have sinned.'</p>",
    "7": "<p><em>ḥāḇôl ḥāḇalnû lāḵ</em>: 'we have acted very corruptly against you.' The infinitive absolute intensifies: literally 'corrupting we have corrupted.' <em>ḥāḇal</em> in the hiphil means to act destructively or corruptly; it frames the community's sin as willful covenant breach. The specific charge: they did not keep (<em>šāmar</em>) the commandments, statutes (<em>ḥuqqîm</em>), and rules (<em>mišpāṭîm</em>) that YHWH commanded Moses. This tripartite legal formula (commandments/statutes/rules) is the standard Deuteronomic covenant language (Deut 4:1, 5, 14; 6:1), signaling that Nehemiah's prayer operates entirely within the Mosaic covenant framework.</p>",
    "8": "<p><em>zᵉḵār-nāʾ ʾet-haddāḇār ʾašer ṣiwwîtā ʾet-mōšeh ʿaḇdeḵā lēʾmōr</em>: 'remember the word you commanded Moses your servant, saying.' Nehemiah quotes Moses' scatter-gather promise (Deut 30:1-5; cf. Lev 26:33): if unfaithful, YHWH will scatter (<em>pûṣ</em>) the people among the nations — but if they return (<em>šûḇ</em>) to YHWH, he will gather them (<em>qāḇaṣ</em>) even from the ends of heaven. <em>ʾim-timdû</em> is conditional: 'if you are faithless.' The prayer is Scripture-informed — Nehemiah is not improvising petition but reminding YHWH of his own declared covenant terms, a legitimate covenantal argument pattern throughout the Psalms and prophets.</p>",
    "9": "<p><em>wᵉšāmtem waʿăśîtem</em>: 'and return and do.' The gather-promise is activated by repentance: <em>šûḇtem</em> (return, turn) is the Deuteronomic repentance verb. The promise: <em>wᵉqibbāṣtîm</em>, 'I will gather them.' The specific destination phrase <em>ʾel-hammāqôm ʾašer-bāḥartî lᵉšakkēn šemî šām</em>, 'to the place I have chosen to cause my name to dwell there,' is the Deuteronomic temple formula (Deut 12:5, 11; 14:23) — the place is Jerusalem and its temple. The prayer grounds the whole restoration project in the Deuteronomic promise of return.</p>",
    "10": "<p><em>wᵉhēm ʿăḇāḏeḵā wᵉʿammᵉḵā ʾašer pādîtā bᵉkōḥᵃḵā haggāḏôl ûbᵉyāḏᵉḵā haḥăzāqāh</em>: 'they are your servants and your people whom you redeemed by your great power and by your strong hand.' <em>pādîtā</em> (you redeemed) is the exodus vocabulary — <em>pādāh</em> is one of the primary Hebrew words for redemption, used throughout Deuteronomy for YHWH's act of purchasing Israel from Egypt (Deut 7:8; 9:26; 15:15). By invoking the exodus redemption, Nehemiah grounds his petition in YHWH's prior, defining act of commitment to Israel — the exile cannot be the final word because YHWH already proved his redemptive will at the exodus.</p>",
    "11": "<p><em>ʾānnāʾ ʾăḏōnāy tᵉhî nāʾ ʾoznᵉḵā qaššeḇet</em>: 'O Lord, let your ear be attentive.' The prayer concludes with renewed petition: grant success (<em>haṣlaḥ-nāʾ</em>) and mercy (<em>lᵉraḥămîm</em>) before Artaxerxes. The closing note is key: <em>waʾanî hāyîtî mašqeh lammeleḵ</em>, 'and I was the king's cupbearer.' <em>mašqeh</em> (cupbearer, literally 'one who gives to drink') was a position of intimate royal trust — the cupbearer tasted the king's wine to detect poison and therefore had unsupervised access to the royal presence. The Genesis parallel (Gen 40-41) shows the long biblical history of Israelites serving in this role; Nehemiah's position is what makes the prayer for favor with the king theologically significant: he already has access that most Israelites could never obtain.</p>"
  },
  "2": {
    "1": "<p><em>wayhî bᵉḥōḏeš nîsān šᵉnat ʿeśrîm</em>: 'and it came to pass in the month Nisan in the twentieth year.' Nisan is March–April — four months after Kislev (Neh 1:1), indicating Nehemiah prayed and fasted for four months before this moment. The word <em>ḥōḏeš</em> (month, new moon) reflects the lunar calendar. The absence of day notation for the Kislev date but its presence here likely reflects the formal court context. <em>wayyiṭṭaḇ hayyayin lᵉp̄ānāyw</em>: 'and wine was before him' — the cupbearer's professional duty is described with <em>nāśāʾ</em> (lifted, carried), establishing the scene before the king's question.</p>",
    "2": "<p><em>wayyōʾmer lî hammelek maddûaʿ pāneḵā rāʿîm</em>: 'and the king said to me, why is your face sad?' The adjective <em>rāʿîm</em> (literally 'evil' — the same root as <em>rāʿāh</em>, evil/trouble) means here 'troubled' or 'unhappy.' A court servant showing sadness before the king was potentially dangerous — it could be interpreted as displeasure with the king. Nehemiah's response acknowledges this: <em>wayyîrāʾ mᵉʾōḏ</em>, 'and I was very afraid.' The fear is not cowardice but professional realism about court protocol. <em>lōʾ-zulātî kî ʾim-raʿ lēḇ</em>: 'unless it be evil/sadness of heart' — <em>lēḇ</em> (heart) points to interior motivation, the source of the visible grief.</p>",
    "3": "<p><em>haʿîr bêt qiḇrôt-ʾăḇōtay ḥārēḇāh</em>: 'the city of my fathers' graves is desolate.' The appeal to ancestral burial sites is deeply significant in ancient Near Eastern culture — the honor due the dead was connected to maintaining the physical site. <em>bêt qiḇrôt</em> (house of graves) invokes both familial piety and the sacred geography of the land. The walls broken down and gates burned are the same conditions reported by Hanani in ch. 1:3, but now Nehemiah frames them for royal consumption: not as religious failure but as neglect of ancestral heritage — a concept any Persian king would understand.</p>",
    "4": "<p><em>wayyōʾmer lî hammelek ʿal-mah-zeh ʾattāh mᵉḇaqqēš</em>: 'and the king said to me, what are you requesting?' The direct royal invitation to speak is the window Nehemiah sought. His response: <em>wāʾetpallēl ʾel-ʾĕlōhê haššāmayim</em>, 'and I prayed to the God of heaven.' This is the famous 'arrow prayer' — a silent, immediate prayer while the royal conversation was ongoing. The participial force of <em>wayyōʾmer…wāʾetpallēl</em> suggests simultaneous action: the king spoke and Nehemiah prayed in the same moment. The prayer is not narrated; it was the internalization of four months of intercession condensed into a breath. It represents the Nehemiah memoir's most characteristic spiritual pattern: prayer integrated into action rather than preceding it.</p>",
    "5": "<p><em>ʾim-ʿal-hammelek ṭôḇ wᵉʾim-yîṭaḇ ʿaḇdᵉḵā lᵉp̄ānêḵā</em>: 'if it pleases the king, and if your servant has found favor in your sight.' The double politeness formula is standard Achaemenid court language, reflecting the subordination of petitioner to monarch. The specific request: <em>tiślaḥēnî ʾel-yᵉhûḏāh ʾel-ʿîr qiḇrôt-ʾăḇōtay</em>, 'send me to Judah, to the city of my fathers' graves.' The commissioning language <em>šālaḥ</em> (send) parallels YHWH's sending of prophets and Moses — in Neh 2:12 Nehemiah will reflect that God put the journey on his heart. The court sending is the human instrument of the divine commission.</p>",
    "6": "<p><em>wahhašśēgāl yōšeḇet ʾeṣlô</em>: 'and the queen was sitting beside him.' <em>šēgāl</em> is a rare word for queen consort (also in Ps 45:9; Dan 5:2), possibly a loanword from Akkadian <em>šēgaltu</em>. Her presence is noted as part of the narrative context but may also explain the king's more intimate and favorable reception — family settings were more conducive to personal requests. The king set a time (<em>wayyitten-lî zᵉman</em>), indicating a fixed term of absence. Nehemiah's answer of a specific date demonstrates advance preparation: the request was not impulsive but carefully planned during the four months of prayer.</p>",
    "7": "<p><em>ʾigᵉrôt ʾel-paḥôt ʿēḇer hannāhār</em>: 'letters to the governors of Beyond the River.' <em>paḥôt</em> is the administrative title for Persian provincial governors (from Old Persian <em>frataraka</em> or Akkadian <em>bēl pāḥāti</em>). <em>ʿēḇer hannāhār</em> (Beyond the River / Trans-Euphrates) was the standard Persian satrapy name for the territory west of the Euphrates including Judah. The letters are safe-conduct documents (<em>yitten-lî ʿādê ʾašer-ʾeḇôr</em>: 'let them give me passage until I arrive'). Nehemiah's insistence on royal documentation reflects Persian bureaucratic procedure: official travel required written authorization.</p>",
    "8": "<p><em>wᵉʾigeret ʾel-ʾāsāp̄ šōmēr happardēs ʾašer lammeleḵ</em>: 'and a letter to Asaph the keeper of the king's forest.' <em>pardēs</em> is a Persian loanword (Old Persian <em>pairi-daēza</em>, enclosed garden/park) appearing in Hebrew only here, in Eccl 2:5, and Song 4:13. It entered Greek as <em>paradeisos</em> and English as 'paradise.' The king's forest provided the timber (beams/<em>qôrôt</em>) for the city gates, the citadel adjacent to the temple, and Nehemiah's own house. The phrase <em>wᵉyaḏ ʾĕlōhay haṭṭôḇāh ʿālay</em>, 'and the good hand of my God was upon me' — <em>yaḏ</em> (hand) as instrument of divine favor is a characteristic Ezra-Nehemiah theological formula (Ezra 7:6, 9, 28; 8:18, 22, 31; Neh 2:18).</p>",
    "9": "<p><em>rišyôn</em> is not an attested Hebrew word in this form — the text likely refers to the <em>ʾigᵉrôt</em> (letters) of v.7-8, which functioned as official authorization. The word <em>šārê hayyām</em> (commanders of the army) indicates a military escort, consistent with Persian practice for important administrative officials traveling through potentially unstable provinces. The escort demonstrates that Nehemiah traveled with imperial backing, not as a private individual — the mission had royal weight.</p>",
    "10": "<p><em>wayyiśmaʿ sanballat haḥōrōnî wᵉṭôḇiyyāhû haʿeḇeḏ hāʿammōnî</em>: 'Sanballat the Horonite and Tobiah the Ammonite servant heard.' <em>Sanballat</em> (<em>Sin-uballiṭ</em> = 'the moon-god gives life') was the governor of Samaria; his Babylonian theophoric name indicates the syncretistic religious environment of the post-exilic region. A papyrus from Elephantine (408 BCE) confirms a Sanballat as governor of Samaria with sons named Delaiah and Shelemiah — Hebrew names suggesting the family maintained Yahwistic religious identity despite Babylonian names. <em>Ṭôḇiyyāhû</em> = 'YHWH is good' — also a Yahwistic name, but he is designated <em>haʿeḇeḏ hāʿammōnî</em>, 'the Ammonite servant' (possibly a derogatory administrative title). Their response: <em>wayyēraʿ lāhem</em>, 'it was evil to them,' — displeasure at someone seeking good for Israel.</p>",
    "11": "<p><em>wāʾāḇôʾ yᵉrûšālaim wāʾehî šām yāmîm šᵉlōšāh</em>: 'and I came to Jerusalem and was there three days.' The three-day waiting period before action is a biblical narrative convention marking time for transition, orientation, and preparation (cf. Josh 1:11; Ezra 8:15). Nehemiah does not immediately convene the leaders or present his commission — he waits, observes, and assesses privately before any public announcement. This deliberate delay reflects strategic thinking: the opposition (Sanballat, Tobiah) is already known to be present, and premature disclosure would allow countermeasures.</p>",
    "12": "<p><em>waʾāqûm laylāh ʾanî waʾănāšîm mᵉʿaṭ</em>: 'and I arose by night, I and a few men.' The night inspection is a strategic secrecy measure. The key phrase: <em>wᵉʾet-habᵉhēmāh ʾašer ʾanî rōḵēḇ ʿāleyhā</em>, 'and the animal on which I was riding' — singular, suggesting only Nehemiah had a mount while the others went on foot. Most importantly: <em>wᵉlōʾ-higgadtî lᵉʾāḏām mah-ʾĕlōhay nōtēn ʾel-libbî laʿăśôt lîrûšālāim</em>, 'and I did not tell anyone what my God was putting in my heart to do for Jerusalem.' <em>libbî</em> (my heart) as the seat of divine motivation — YHWH places the purpose (<em>nōtēn</em>, gives, puts) in the interior person; Nehemiah receives the mission as a God-given burden before any human strategy is formulated.</p>",
    "13": "<p><em>wāʾēṣēʾ bᵉšaʿar haggebay laylāh</em>: 'and I went out by the Valley Gate at night.' The inspection route goes counterclockwise around the southern portion of the city wall. <em>ṯannîn</em> is the Jackal's Well (some translations 'Serpent's Well'; <em>ṯannîn</em> can mean jackal or sea monster, and the toponym is uncertain). The condition of the walls: <em>ûbᵉšāʿārāyw ʾūḵlāh ʾēš</em>, 'and the gates had been devoured by fire.' The verb <em>ʾāḵal</em> (eat, devour) used for the fire's destruction is vivid — the city was consumed. This is eyewitness memoir language preserving the specific emotional experience of seeing the ruins firsthand.</p>",
    "14": "<p><em>wāʾeʿᵉḇōr ʾel-šaʿar hāʾašpōt</em>: 'and I passed on to the Dung Gate.' The Dung Gate (<em>šaʿar hāʾašpōt</em> — <em>ʾašpōt</em> from <em>ʾašpāh</em>, dunghill or refuse heap) was located at the southern tip of the city near the Hinnom Valley, where waste was disposed. The condition Nehemiah found: <em>wᵉʾên-māqôm labbᵉhēmāh laʿăḇōr taḥtāy</em>, 'and there was no place for the animal under me to pass.' The rubble was so extensive the mount could not navigate it — Nehemiah had to dismount and inspect on foot. This physical detail authenticates the memoir's eyewitness character.</p>",
    "15": "<p><em>wāʾeĕhî ʿōleh bannāḥal laylāh</em>: 'and I went up by the Kidron Valley at night.' After the Dung Gate, Nehemiah turned back through the Valley/Kidron, inspecting the eastern wall section. <em>wāʾāšûḇ waʾāḇôʾ bᵉšaʿar haggay</em>: 'and I turned back and entered through the Valley Gate.' The inspection was cut short by the impassability of the southern section. The route covered reveals which portions of the wall were most severely damaged: the southern and southwestern sections near the Dung Gate.</p>",
    "16": "<p><em>wᵉhassᵉgānîm lōʾ yāḏᵉʿû ʾānāh hālaḵtî</em>: 'and the officials did not know where I had gone.' <em>sᵉgānîm</em> (officials, prefects) are the local administrative leaders. The secrecy is maintained even from sympathetic leaders. Three categories of leaders are listed: <em>sᵉgānîm</em> (officials), <em>hiyhûḏîm</em> (Jews generally), <em>kōhănîm</em> (priests), <em>ḥōrîm</em> (nobles), and <em>sᵉgānîm</em> again in the v.17 address. The careful enumeration of the social hierarchy reflects the need to unite all sectors of Judean society behind the project.</p>",
    "17": "<p><em>wāʾōmar ʾălêhem ʾattem rōʾîm hārāʿāh ʾašer ʾănaḥnû ʾûhă</em>: 'and I said to them, you see the trouble in which we are.' The pronoun shift is significant: Nehemiah uses 'we' (<em>ʾănaḥnû</em>) throughout — he identifies himself completely with the community he came to serve. The diagnosis: Jerusalem is desolate (<em>ḥārēḇāh</em>), its gates burned. The appeal: <em>lᵉḵû wᵉniḇneh ʾet-ḥômat yᵉrûšālaim</em>, 'come, let us build the wall of Jerusalem.' The hortatory cohortative (<em>niḇneh</em>) invites collective ownership of the project. The shame argument: <em>wᵉlōʾ nihyeh ʿôḏ ḥerpāh</em>, 'that we may no longer be a reproach.' <em>ḥerpāh</em> (shame, reproach) is the motivating term — the community's honor is bound up with the city's defenses.</p>",
    "18": "<p><em>wāʾaggîḏ lāhem ʾet-yaḏ ʾĕlōhay ʾăšer-hāyᵉṯāh ṭôḇāh ʿālay</em>: 'and I told them of the hand of my God that was good upon me.' <em>yaḏ ʾĕlōhîm</em> (the hand of God) as a formula of divine favor and enablement appears seven times in Ezra-Nehemiah (Ezra 7:6, 9, 28; 8:18, 22, 31; Neh 2:8, 18). The formula balances divine initiative with human action: YHWH's good hand is evident in the royal authorization Nehemiah received. The community's response: <em>wayyaḥazzᵉqû yᵉdêhem laṭṭôḇāh</em>, 'and they strengthened their hands for the good work' — the <em>ḥāzaq</em> idiom (strengthen/encourage) will become the dominant verb in the wall-building narrative of ch. 3.</p>",
    "19": "<p><em>wayyiśmaʿ sanballat haḥōrōnî wᵉṭôḇiyyāh hāʿeḇeḏ hāʿammōnî wāgeśem hāʿarāḇî</em>: 'Sanballat the Horonite, Tobiah the Ammonite servant, and Geshem the Arab heard.' A new opponent: <em>Geshem the Arab</em> (<em>gašmû</em> in 6:6) — archaeological evidence identifies a Qedarite Arab confederacy with a leader named <em>Gashm</em> who controlled the territory south and east of Judah ca. 445 BCE (a silver bowl inscription from the eastern Nile Delta reads <em>qyn br gšm mlk qdr</em>, 'Qainu son of Geshem, king of Qedar'). The triple opposition represents the three geographic threats: north (Sanballat/Samaria), east (Tobiah/Ammon), south (Geshem/Arabia). Their tactic: <em>wayyal<sup>e</sup>gû bānû wayyiḇzû</em>, 'they mocked us and despised us,' then the accusation of rebellion.</p>",
    "20": "<p><em>wāʾāšîḇ ʾōtām dāḇār</em>: 'and I replied to them.' The triple exclusion formula that follows is one of Nehemiah's most rhetorically forceful statements: (1) <em>ʾĕlōhê haššāmayim hûʾ yaṣlîaḥ lānû</em>, 'the God of heaven will make us prosper'; (2) <em>waʾănaḥnû ʿăḇāḏāyw nāqûm ûḇānînû</em>, 'and we his servants will arise and build'; (3) the exclusion itself — <em>wᵉlakem ʾên-ḥēleq wᵉṣᵉḏāqāh ûzikkārôn bîrûšālāim</em>, 'but you have no portion, right, or memorial in Jerusalem.' Three Hebrew terms: <em>ḥēleq</em> (portion/share — legal stake in the community), <em>ṣᵉḏāqāh</em> (righteousness/right — legitimate claim), <em>zikkārôn</em> (memorial/remembrance — historical continuity). The triple exclusion is a legal formula barring the opponents from any claim on Jerusalem's future — they have no stake, no right, and no history in the city.</p>"
  },
  "3": {
    "1": "<p><em>wayyāqom ʾelyāšîḇ hakkōhēn haggāḏôl wᵉʾeḥāyw hakkōhănîm wayyiḇnû ʾet-šaʿar haṣṣōʾn</em>: 'and Eliashib the high priest arose with his fellow priests and they built the Sheep Gate.' The chapter's governing verb is <em>ḥāzaq</em> (strengthen, repair, fortify) — used 35 times in this chapter as the technical term for wall repair. <em>qiḏᵉšûhû</em>: 'they dedicated/consecrated it' — the Sheep Gate uniquely receives the verb <em>qāḏaš</em> (to set apart as holy), appropriate since the high priest and priests built it and it was the entry point for sacrificial animals going to the temple. The consecration also applies to the towers flanking it. <em>miggaddal hamêʾāh</em> (Tower of the Hundred) and <em>miggaddal ḥananʾēl</em> (Tower of Hananel) are probably the northeastern corner towers of the city.</p>",
    "2": "<p><em>wᵉʿal-yāḏô bānû ʾanšê yᵉrîḥô</em>: 'and next to him the men of Jericho built.' The phrase <em>ʿal-yāḏô</em> (literally 'at his hand' = next to him) is the standard construction formula for the chapter, indicating each section's adjacency to the previous worker. The men of Jericho represent the broader district workers from outside Jerusalem proper who contributed to the project — the wall-building was a national Judean effort, not merely a local Jerusalem project. <em>waʿal-yāḏô ḥāzaq zakkûr ben-ʾimmrî</em>: Zaccur son of Imri, a Levite, built the next section.</p>",
    "3": "<p><em>wᵉʾet-šaʿar haddāgîm bānû bᵉnê hassᵉnāʾāh</em>: 'and the sons of Hassenaah built the Fish Gate.' <em>šaʿar haddāgîm</em> (Fish Gate) was located on the northern wall where the fish market operated (cf. Zeph 1:10). The construction detail is precise: <em>hēm qērûhû wayyaʿămîḏû daltōtāyw manʿûlāyw ûbᵉrîḥāyw</em>, 'they laid its beams and set its doors, its locks, and its bars.' The four components — <em>qôrôt</em> (beams), <em>daltôt</em> (doors/leaves), <em>manʿûlîm</em> (bolts, from <em>nāʿal</em> to fasten), <em>bᵉrîḥîm</em> (bars, cross-bars) — constitute the full security apparatus of a city gate.</p>",
    "4": "<p><em>wᵉʿal-yāḏām ḥāzaq mᵉrēmôt ben-ʾûriyyāh ben-haqqôṣ</em>: 'and next to them Meremoth son of Uriah son of Hakkoz repaired.' Meremoth appears again in v.21, building a second section — unusual zeal. He also appears in Ezra 8:33 receiving the temple treasures Ezra brought from Babylon. The Ben-Hakkoz family appears in Ezra 2:61 among the priests who could not prove their genealogy (and were therefore barred from the priesthood) — yet Meremoth served faithfully. <em>waʿal-yāḏô ḥāzaq mešullām ben-bᵉreḵyāh ben-mešêzaḇʾēl</em>: Meshullam son of Berechiah, who also built a second section (v.30). His daughter married Tobiah's son (Neh 6:18), creating an irony: a man who built the wall had family ties to the primary opponent.</p>",
    "5": "<p><em>waʿal-yāḏām ḥāzaq hattᵉqôʿîm wᵉʾaddîrêhem lōʾ-hēḇîʾû ṣawwᵉʾrām bᵉʿăḇōḏat ʾăḏōnêhem</em>: 'and next to them the Tekoites repaired, but their nobles did not bring their neck to the work of their Lord.' This is the one negative note in the wall-building record. <em>ʾaddîrîm</em> (nobles, great ones) refused to participate; the metaphor is vivid: they would not 'bring their neck' (<em>lōʾ-hēḇîʾû ṣawwᵉʾrām</em>), i.e., bend to the yoke of labor. Yet the Tekoite common workers built not only their assigned section here (v.5) but also a second section (v.27) — the ordinary citizens compensated for the nobles' refusal. Tekoa was 12 miles south of Jerusalem, a pastoral town (Amos was from Tekoa); its distance made the workers' participation more remarkable.</p>",
    "6": "<p><em>wᵉʾet-šaʿar hayšānāh ḥizzᵉqû yôyāḏāʿ ben-pāsēaḥ ûmešullām ben-bᵉsôḏyāh</em>: 'and the Old Gate was repaired by Joiada son of Paseah and Meshullam son of Besodeiah.' <em>šaʿar hayšānāh</em> (Gate of the Old/Jeshanah) is obscure — some identify it with the Mishneh (Second Quarter) gate; the Hebrew <em>yāšān</em> means old. The construction details: <em>hēm ‌ṭāḥᵉnûhû wayyaʿămîḏû daltōtāyw manʿûlāyw ûḇrîḥāyw</em> — same formula as v.3, indicating a standardized construction record, likely drawn from an official list maintained during the project.</p>",
    "7": "<p><em>waʿal-yāḏām ḥāzaq mᵉlaṭyāh haggiḇʿônî wᵉyāḏôn hamêrônōṯî ʾanšê giḇʿôn ûhammiṣpāh</em>: 'and next to them Melatiah the Gibeonite and Jadon the Meronothite repaired, the men of Gibeon and Mizpah.' Gibeon and Mizpah are northwest of Jerusalem, in Benjamin territory. The phrase that follows is textually difficult: <em>lᵉkissēʾ paḥat ʿēḇer hannāhār</em>, 'belonging to the throne/seat of the governor of Beyond the River' — possibly indicating these towns fell under the direct jurisdiction of the Persian province rather than the local Jerusalem administration. The inclusion of Benjaminite towns reflects the ethnic-geographic breadth of the project.</p>",
    "8": "<p><em>ʿal-yāḏô ḥāzaq ʿuzzîʾēl ben-ḥarhayāh ṣōrᵉp̄îm</em>: 'next to him Uzziel son of Harhaiah, goldsmiths (<em>ṣōrᵉp̄îm</em>).' The mention of professional guilds — goldsmiths (<em>ṣōrᵉp̄îm</em>, from <em>ṣārap̄</em> to refine/smelt) and perfumers (<em>rōqᵉḥîm</em>, from <em>rāqaḥ</em> to mix/compound) — indicates that the artisan guilds of Jerusalem participated in the wall project alongside priests, officials, and farmers. <em>wayyaʿăzᵉḇû yᵉrûšālaim ʿad-haḥômāh hārᵉḥāḇāh</em>: 'and they restored Jerusalem as far as the Broad Wall.' The Broad Wall (<em>haḥômāh hārᵉḥāḇāh</em>) was a massive 8th-century BCE fortification on the northwest; archaeological excavations have confirmed its existence at approximately 7 meters wide.</p>",
    "9": "<p><em>wᵉʿal-yāḏām ḥāzaq rᵉp̄āyāh ben-ḥûr śar ḥᵉṣî peleḵ yᵉrûšālaim</em>: 'and next to them Rephaiah son of Hur, ruler of half the district of Jerusalem.' <em>śar ḥᵉṣî peleḵ</em>: 'ruler of half the district' — <em>peleḵ</em> is a Persian administrative term (possibly from Akkadian) for a sub-district. Jerusalem's district was divided into two halves, each with its own ruler (cf. v.12: Shallum, ruler of the other half). The dual administration reflects Persian provincial organization at the local level.</p>",
    "10": "<p><em>waʿal-yāḏô ḥāzaq yᵉḏāʿyāh ben-ḥărûmap̄ wᵉnegeḏ bêtô</em>: 'and next to him Jedaiah son of Harumaph repaired, and opposite his own house.' The phrase <em>negeḏ bêtô</em> (opposite his own house) is the chapter's most humanizing detail — individuals and families built the section of wall adjacent to their own homes. This had obvious practical motivation (you protect your own door first) but also created personal ownership of the project: each homeowner's section was their responsibility. <em>Ḥattûš ben-ḥašabnᵉyāh</em> built next to him.</p>",
    "11": "<p><em>ḥēzeq šēnî ḥāzaq malkiyyāh ben-ḥārîm wᵉḥaššûb ben-paḥat-môʾāḇ</em>: 'Malchijah son of Harim and Hasshub son of Pahath-moab repaired a second section.' <em>ḥēzeq šēnî</em> is unique — only here in the chapter does a worker build a 'second section' (not a separate second assignment, but a stretch adjoining the first). The Tower of the Ovens (<em>migdal hatannûrîm</em>) was likely a tower named for the bakers' quarter nearby; <em>tannûr</em> is the clay oven used for baking bread, still used as the standard oven type (<em>tannur</em>) in the Middle East.</p>",
    "12": "<p><em>waʿal-yāḏô ḥāzaq šallûm ben-hallôḥēš śar ḥᵉṣî peleḵ yᵉrûšālaim hûʾ ûḇᵉnôtāyw</em>: 'and next to him Shallum son of Hallohesh, ruler of the other half-district of Jerusalem, he and his daughters.' <em>ûḇᵉnôtāyw</em> (and his daughters) is the chapter's most remarkable detail — women explicitly participating in the heavy labor of wall construction. No other text in the OT records women in physical construction work. The daughters are unnamed but their contribution is permanently recorded. This detail may also explain the intense personal motivation: when the family unit builds together on the section protecting their own home, the work transcends the administrative and becomes familial devotion.</p>",
    "13": "<p><em>ʾet-šaʿar haggay ḥizzᵉqû ḥānûn wᵉyōšᵉḇê zānôaḥ</em>: 'the Valley Gate was repaired by Hanun and the inhabitants of Zanoah.' Hanun is possibly the same official named in Neh 2:13 as the starting point of Nehemiah's nocturnal inspection. Zanoah was a village in the Shephelah region. The section length is given: <em>ʾelep̄ ammāh</em>, 'a thousand cubits' (approximately 500 meters) — the longest assigned section in the chapter, suggesting either Zanoah provided exceptional manpower or this stretch was less damaged. <em>ʿad šaʿar hāʾašpōt</em>: up to the Dung Gate, establishing the southern wall assignment.</p>",
    "14": "<p><em>wᵉʾet-šaʿar hāʾašpôt ḥizzᵉq malkiyyāh ben-rēḵāb śar peleḵ bêt-hakkārem</em>: 'and the Dung Gate was repaired by Malchijah son of Rechab, ruler of the district of Beth-haccherem.' Beth-haccherem is possibly identified with modern Ramat Rachel, a site south of Jerusalem. Malchijah is a district ruler — the Persian administrative structure of Judah (the <em>medinah</em>) included several sub-districts, each contributing labor proportional to their administrative unit. The Dung Gate was the lowest-prestige gate of the city (located near the rubbish dumps); its assignment to a district ruler rather than a local figure may reflect the organizational pragmatics of the project.</p>",
    "15": "<p><em>wᵉʾet-šaʿar hāʿayin ḥizzᵉq šallûn ben-kôl-ḥōzeʾ śar peleḵ hammiṣpāh</em>: 'and the Fountain Gate was repaired by Shallun son of Col-hozeh, ruler of the district of Mizpah.' The Fountain Gate (<em>šaʿar hāʿayin</em>) opened near the Gihon spring, Jerusalem's primary water source. <em>hûʾ yiḇnennû wᵉyiṣōpennû</em>: 'he built it and roofed it' — the Fountain Gate received special treatment beyond other gates, with a roof added. <em>wᵉdaltōtāyw manʿûlāyw ûḇᵉrîḥāyw</em> — the standard gate hardware. The Pool of Shelah (<em>bᵉrêḵat haššelaḥ</em>) and the king's garden are mentioned as landmarks; <em>Šelaḥ</em> (= Siloam) connects to Hezekiah's tunnel system.</p>",
    "16": "<p><em>ʾaḥărāyw ḥāzaq nᵉḥemyāh ben-ʿazḇûq śar ḥᵉṣî peleḵ bêt-ṣûr</em>: 'after him Nehemiah son of Azbuk, ruler of half the district of Beth-zur.' This Nehemiah is not the author of the book — the memoir author carefully uses first-person (<em>ʾanî</em>) when referring to himself. Beth-zur was an important city in Judah (about 25 km south of Jerusalem). This Nehemiah built <em>ʿad-negeḏ qiḇrê ḏāwîḏ</em> (opposite the tombs of David) — the royal tombs on the eastern slope of the City of David are here confirmed as still identifiable landmarks in the 5th century BCE.</p>",
    "17": "<p><em>ʾaḥărāyw ḥāzᵉqû halwiyyim rᵉḥûm ben-bānî</em>: 'after him the Levites repaired — Rehum son of Bani.' The Levitical participation in wall-building alongside their liturgical duties reflects the holistic community organization Nehemiah achieved. <em>ʾal-yāḏô ḥāzaq ḥašabyāh śar ḥᵉṣî peleḵ qᵉʿîlāh</em>: 'next to him Hashabiah, ruler of half the district of Keilah' — Keilah is the city that David once defended (1 Sam 23). Its ruler's participation in Jerusalem's wall shows the provincial solidarity of the Judean districts with the capital.</p>",
    "18": "<p><em>ʾaḥărāyw ḥāzᵉqû ʾăḥêhem bawway ben-hênaḏāḏ śar ḥᵉṣî peleḵ qᵉʿîlāh</em>: 'after them their brothers repaired: Binnui son of Henadad, ruler of the other half-district of Keilah.' The Henadad family appears in Ezra 3:9 as Levites who supervised temple rebuilding — a family with a multi-generational record of service to the restoration. Binnui (<em>binnûy</em> = 'built up,' a fitting name for a wall-builder) completed the Keilah district's contribution alongside Hashabiah.</p>",
    "19": "<p><em>wayyaḥᵉzeq ʿal-yāḏô ʿezer ben-yêšûaʿ śar hammiṣpāh middāh šēnît</em>: 'and next to him Ezer son of Jeshua, ruler of Mizpah, repaired a second section.' <em>middāh šēnît</em> (second section/measured portion) — <em>middāh</em> (measure, portion) is the chapter's technical term for a work assignment. The section extended from the angle (<em>hammiqṣôaʿ</em>) to the door of the armory (<em>pᵉtaḥ bêt haggibôr</em>), i.e., the military garrison's entry — a key defensive installation.</p>",
    "20": "<p><em>ʾaḥărāyw ḥāzaq bārûḵ ben-zabbay middāh šēnît minhammiqṣôaʿ ʿad-pᵉtaḥ bêt-ʾelyāšîḇ hakkōhēn haggāḏôl</em>: 'after him Baruch son of Zabbai repaired a second measured section, from the angle to the door of the house of Eliashib the high priest.' The phrase <em>ḥeḥĕrāh</em> (he repaired zealously / with ardor) is unique — only Baruch is described with this intensifier. The root <em>ḥārāh</em> usually means to be angry or to burn; here it likely means 'with fervor' or 'zealously.' Baruch's exceptional devotion is singled out as worthy of note within a chapter of devoted workers.</p>",
    "21": "<p><em>ʾaḥărāyw ḥāzaq mᵉrēmôt ben-ʾûriyyāh ben-haqqôṣ middāh šēnît mipᵉtaḥ bêt-ʾelyāšîḇ wᵉʿad-tōsep̄ bêt-ʾelyāšîḇ</em>: 'after him Meremoth son of Uriah son of Hakkoz repaired a second section, from the door of Eliashib's house to the end of Eliashib's house.' Meremoth is the only worker who explicitly appears twice in the chapter on separate sections (vv.4 and 21). His exceptional contribution is consistent with his role in Ezra 8:33 as the priest responsible for weighing and recording the temple treasures — a man of established trustworthiness and initiative.</p>",
    "22": "<p><em>wᵉʾaḥărāyw ḥāzᵉqû hakkōhănîm ʾanšê hakkikkār</em>: 'and after him the priests, the men of the surrounding region, repaired.' <em>Hakkikkār</em> is the plain/circuit around Jerusalem — the valley district. The priests built the section of wall running past their own houses, maintaining the pattern of personal stake driving personal labor. Their participation alongside lay workers, Levites, merchants, and artisans reflects Nehemiah's ability to unite the entire social structure behind the common project.</p>",
    "23": "<p><em>ʾaḥărāyw ḥāzaq binyāmîn wᵉḥaššûḇ negeḏ bêtām</em>: 'after him Benjamin and Hasshub repaired, opposite their house.' The <em>negeḏ bêtô / bêtām</em> (opposite his/their house) formula returns — the household-assignment principle documented throughout the chapter. <em>ʾaḥărāyw ḥāzaq ʿăzaryāh ben-maʿăśêyāh ben-ʿănanyāh ʾēṣel bêtô</em>: Azariah son of Maaseiah son of Ananiah repaired next to his house. <em>ʾēṣel</em> (beside) rather than the usual <em>negeḏ</em> (opposite) — a slight variation suggesting his section was adjacent to rather than facing his residence.</p>",
    "24": "<p><em>ʾaḥărāyw ḥāzaq binnûy ben-hênaḏāḏ middāh šēnît mibêt ʿăzaryāh ʿad-hammiqṣôaʿ wᵉʿad-hapinnāh</em>: 'after him Binnui son of Henadad repaired a second section, from Azariah's house to the angle and to the corner.' Binnui (also in v.18 as a district ruler) appears again here — whether this is the same person building a second assignment or a different Binnui in the Henadad family is debated. The landmarks — the angle (<em>hammiqṣôaʿ</em>) and the corner (<em>hapinnāh</em>) — were architectural features of the wall circuit used as reference points in the official building record.</p>",
    "25": "<p><em>pālāl ben-ʿûzay minnegeḏ hammiqṣôaʿ wᵉhammigdāl hayyôṣēʾ mibêt hammelek hāʿelyônāh</em>: 'Palal son of Uzai repaired opposite the angle and the tower projecting from the upper house of the king.' The upper royal palace (<em>bêt hammelek hāʿelyônāh</em>) was the administrative structure on the southeastern hill; the projecting tower (<em>hammigdāl hayyôṣēʾ</em>) was a defensive fortification protecting the palace approach. <em>Peḏāyāh ben-parʿōš</em> built the adjacent section from the court of the guard (<em>ḥăṣar hammmaṭṭārāh</em>), which was a known Jerusalem landmark (Jer 32:2, 8, 12; 33:1; 37:21; 38:6, 13, 28).</p>",
    "26": "<p><em>wᵉhannᵉtînîm hayyôšᵉḇîm bāʿōp̄el ʿad-negeḏ šaʿar hammayim</em>: 'and the temple servants living on the Ophel repaired up to opposite the Water Gate.' The Nethinim (<em>nᵉtînîm</em> = 'given ones,' those dedicated to temple service — possibly descendants of Solomon's Canaanite laborers or prisoners of war assigned to temple duties, Ezra 8:20) lived on the Ophel, the hill between the City of David and the temple mount. Their participation in wall-building continued beyond their assigned section: <em>wᵉhammigdāl hayyôṣēʾ</em>, the projecting tower. The Water Gate (<em>šaʿar hammayim</em>) led to the Gihon spring; it becomes important in Neh 8:1, 3, 16 as the assembly point for Ezra's public Torah reading.</p>",
    "27": "<p><em>ʾaḥărāyw ḥāzᵉqû hattᵉqôʿîm middāh šēnît minnegeḏ hammigdāl haggāḏôl hayyôṣēʾ wᵉʿad ḥômat hāʿōp̄el</em>: 'after them the Tekoites repaired a second section, from opposite the great projecting tower to the wall of the Ophel.' The Tekoites reappear — despite their nobles' refusal to serve (v.5), the common workers built not only their original section but also a second one. The contrast is pointed: the nobles who refused to bend their necks are permanently recorded as shirkers; the workers who doubled their effort are recorded as faithful. The community saw and remembered both.</p>",
    "28": "<p><em>mēʿal šaʿar hassûsîm ḥāzᵉqû hakkōhănîm</em>: 'above the Horse Gate the priests repaired.' The Horse Gate (<em>šaʿar hassûsîm</em>) was on the eastern wall of the temple mount, providing access to the royal stables — each priest repaired the section opposite his own house (<em>negeḏ bêtô</em>). This is the second mention of priests building opposite their own houses (cf. v.22), reflecting that priestly residences were distributed along the eastern wall adjacent to the temple complex.</p>",
    "29": "<p><em>ʾaḥărāyw ḥāzaq ṣāḏôq ben-ʾimmēr negeḏ bêtô</em>: 'after him Zadok son of Immer repaired, opposite his own house.' <em>ʾaḥărāyw ḥāzaq šᵉmayāh ben-šeḵanyāh šōmēr šaʿar hammizrāḥ</em>: 'after him Shemaiah son of Shecaniah, keeper/guardian of the East Gate, repaired.' <em>šōmēr šaʿar</em> (gatekeeper) was a formal Levitical office (1 Chr 9:17-27); the gatekeeper repaired the very gate he was responsible for guarding — a fitting union of function and labor.</p>",
    "30": "<p><em>ʾaḥărāyw ḥāzaq ḥananeyāh ben-šelemyāh waḥānûn ben-ṣālāp̄ haššišší</em>: 'after him Hananiah son of Shelemiah and Hanun son of Zalaph the sixth repaired.' <em>haššišší</em> (the sixth) designates Zalaph's birth order in the family — an unusually specific genealogical marker that suggests Hanun is identified by family position to distinguish him from other men named Hanun. <em>ʾaḥărāyw ḥizzᵉq mešullām ben-bᵉreḵyāh negeḏ niškātô</em>: Meshullam son of Berechiah repaired his second section opposite his chamber (<em>niškāh</em>). <em>Niškāh</em> (storage room, cell) indicates Meshullam had a room within the temple precincts — a common arrangement for priests and officials.</p>",
    "31": "<p><em>ʾaḥărāyw ḥāzaq malkiyyāh ben-haṣṣōrᵉp̄î ʿad-bêt hannᵉtînîm wᵉhārōkᵉlîm negeḏ šaʿar hammipqāḏ wᵉʿad ʿăliyyat happinnāh</em>: 'after him Malchijah the son of the goldsmith repaired as far as the house of the temple servants and the merchants, opposite the Muster Gate and as far as the upper room of the corner.' The <em>Muster Gate</em> (<em>šaʿar hammipqāḏ</em>, also 'Inspection Gate' from <em>pāqaḏ</em> = to number/muster/appoint) was the gate through which the troops were reviewed. The goldsmiths' and merchants' quarter near the temple reflects the commercial activity that naturally clustered near the sacrificial and pilgrimage center.</p>",
    "32": "<p><em>ûḇên ʿăliyyat happinnāh lᵉšaʿar haṣṣōʾn ḥāzᵉqû haṣṣōrᵉp̄îm wᵉhārōkᵉlîm</em>: 'and between the upper room of the corner and the Sheep Gate the goldsmiths and the merchants repaired.' The chapter ends where it began — the Sheep Gate in v.1. The circuit is complete. The goldsmiths and merchants built the final stretch, closing the ring. The chapter as a whole is a theological document disguised as a building record: 41 named individuals and groups, priests and servants, rulers and artisans, men and women, locals and visitors — all united in the single task of reconstituting the city's defenses under YHWH's good hand.</p>"
  },
  "4": {
    "1": "<p><em>wayhî kaʾašer šāmaʿ sanballat kî-ʾănaḥnû bônîm ʾet-hahômāh wayyiḥar lô</em>: 'and it came about that when Sanballat heard that we were building the wall, he was angry.' <em>wayyiḥar lô</em> is the idiom for anger — literally 'it burned for him' (<em>ḥārāh</em> = to burn, be angry). The anger vocabulary intensifies: <em>kāʿas gāḏôl</em> (great vexation, provocation) in v.1 — <em>kāʿas</em> is the emotional disturbance of someone who sees their position threatened. Sanballat's reaction is public and deliberate: <em>yᵉdabbēr lip̄nê ʾăḥāyw ûḇêl samaryîn</em>, 'he spoke before his brothers and the army of Samaria' — the mockery is addressed to the Samaritan military establishment, intended to delegitimize the project politically before it gains momentum.</p>",
    "2": "<p><em>wayyōʾmer mah-hāyᵉhûḏîm hāʾumᵉlālîm ʿōśîm</em>: 'and he said, what are these feeble Jews doing?' <em>ʾumᵉlāl</em> (feeble, powerless) comes from <em>ʾāmal</em>, to languish or be enfeebled — a term of contempt. The series of rhetorical questions parses the impossibility of the project: (1) Will they fortify themselves? (2) Will they sacrifice? (3) Will they finish in a day? (4) Will they revive the stones from the heaps of rubble? The fourth question is particularly pointed: <em>hayᵉḥayyû ʾet-hāʾăḇānîm mēʿarᵉmôt hāʿāp̄ār</em>, 'will they revive the stones from the piles of ash/dust?' The rubble was not usable building material — it had been burned and shattered. Sanballat's questions may reflect genuine strategic assessment: the project was technically improbable.</p>",
    "3": "<p><em>wᵉṭôḇiyyāh hāʿammōnî ʾeṣlô wayyōʾmer gam ʾašer-hēm bônîm ʾim-yaʿăleh šûʿāl ûp̄āraṣ ḥômat ʾaḇnêhem</em>: 'and Tobiah the Ammonite was beside him and said, even what they are building — if a fox goes up, it would breach their stone wall.' The fox simile (<em>šûʿāl</em> = fox or jackal) is a merciless attack on the quality of the construction: the walls are so poorly built that even the weight of a small animal would collapse them. <em>ûp̄āraṣ</em> (would breach) — the verb used of a military breach; the irony is a wild animal causing a military-grade collapse. The dismissal was both tactical (demoralization) and possibly accurate: rubble-built walls without proper mortar or foundations would be structurally weak.</p>",
    "4": "<p><em>šᵉmaʿ ʾĕlōhênû kî-hāyînû ḇûzāh</em>: 'hear, our God, for we have become an object of contempt.' Nehemiah's imprecatory prayer (vv.4-5) is the most direct of his four prayers in the memoir. <em>ḥerpātām</em> (their reproach) — the same <em>ḥerpāh</em> term from 1:3 and 2:17 now inverted: God should turn their mockery back on their own heads. <em>wᵉhāšēḇ ḥerpātām ʾel-rōʾšām</em>: 'and return their taunt upon their own head.' The prayer calls for covenant retribution: those who shame the covenant people should experience the shame they inflicted. The logic is Deuteronomic — the mockers are attacking YHWH's project, and YHWH's honor is implicated in the wall's outcome.</p>",
    "5": "<p><em>wᵉʾal-tᵉḵas ʿal-ʿăwōnām</em>: 'and do not cover their iniquity.' <em>kāsāh</em> (to cover) is the verb for atonement in some contexts — here Nehemiah prays for the opposite: uncovering, not covering. <em>wᵉḥaṭṭāʾtām mipᵉneḵā ʾal-timmāḥeh</em>: 'and do not let their sin be blotted out from before you.' The prayer echoes Moses' anti-intercession for those who abandon the covenant (cf. Ps 69:28, 'let them be blotted out of the book of the living'). The justification: <em>kî hirkîʾsûnî linegeḏ habbōnîm</em>, 'for they have provoked you to anger before the builders' — the mockery was not private but public, calculated to demoralize, and therefore a public affront to YHWH.</p>",
    "6": "<p><em>wanniḇneh ʾet-hahômāh wattiqṣar kol-hahômāh ʿad-haḥᵉṣyāh</em>: 'so we built the wall, and the entire wall was joined together to half its height.' Despite the mockery, the work continued: <em>wayyᵉḥî lēḇ lāʿām laʿăśôt</em>, 'for the people had a mind/heart to work.' <em>lēḇ</em> (heart/mind) — the interior will to act — is what sustained the project through external opposition. The half-height completion is a significant milestone: the wall now existed as a continuous circuit, even if not full-height. The phrase <em>kol-hahômāh</em> (the entire wall) emphasizes completeness of the circuit before full height was achieved.</p>",
    "7": "<p><em>wayhî kaʾašer šāmaʿ sanballat wᵉṭôḇiyyāh wᵉhāʿărāḇîm wᵉhāʿammônîm wᵉhāʾašdōdîm</em>: 'and it came about that when Sanballat, Tobiah, the Arabs, the Ammonites, and the Ashdodites heard.' The opposition broadens beyond the original three to include the people of Ashdod — the old Philistine city to the west. All four geographic directions are now represented: north (Samaria/Sanballat), east (Ammon/Tobiah), south (Arabia/Geshem), west (Ashdod). <em>kî-ʿālᵉtāh ʾărûḵāh lᵉḥōmôt yᵉrûšālaim</em>: 'that the healing of the walls of Jerusalem was advancing' — <em>ʾārûḵāh</em> (healing, restoration) applied to walls is an unusual metaphor; walls can be 'healed' as a wound heals, closing the breach.</p>",
    "8": "<p><em>wayyiqqāšᵉrû kullām yaḥdāw lāḇôʾ lᵉhillāḥēm bîrûšālaim wᵉlaʿăśôt-lô tôʿāh</em>: 'and they conspired together to come and attack Jerusalem and cause confusion in it.' <em>qāšar</em> (to conspire, bind together) signals a coalition plot. Two objectives: <em>lᵉhillāḥēm</em> (to fight) and <em>laʿăśôt-lô tôʿāh</em> (to create confusion/disorder). <em>Tôʿāh</em> (confusion, error, disturbance) is the strategy of sowing disorganization within the workforce — not merely a military attack but a psychological campaign to disrupt the project's coordination.</p>",
    "9": "<p><em>wannitpallēl ʾel-ʾĕlōhênû wannaʿămîḏ mišmār ʿălêhem yômām wālaylāh mippᵉnêhem</em>: 'and we prayed to our God and posted a guard against them day and night because of them.' The two responses are parallel and simultaneous: prayer (<em>hitpallēl</em>) and practical defense (<em>mišmār</em> = guard duty). Nehemiah does not contrast prayer and action as alternatives — they are paired. The prayer is not instead of the guard; the guard is not instead of prayer. <em>Mišmār</em> (guard, watch) is both noun and concept; its day-and-night character means continuous vigilance, no gaps. The Ephesians 6:18 parallel ('praying at all times…with all perseverance, making supplication for all the saints') captures exactly this dual posture.</p>",
    "10": "<p><em>wayyōʾmer yᵉhûḏāh kāšal kōaḥ hansabbāl wᵉhāʿāp̄ār harbēh wᵉʾănaḥnû lōʾ nûḵal liḇnôt baḥômāh</em>: 'and Judah said, the strength of the laborers is failing and there is much rubble, and we ourselves cannot build the wall.' This verse represents the internal discouragement within the workforce — a complaint from the builders of Judah themselves. Three problems: (1) physical exhaustion (<em>kāšal kōaḥ</em> = stumbling/failing strength), (2) overwhelming rubble (<em>hāʿāp̄ār harbēh</em> = much dust/debris), (3) self-doubt (<em>lōʾ nûḵal</em> = we are not able). The laborers' complaint is realistic; the project had now continued long enough for fatigue to set in alongside external opposition.</p>",
    "11": "<p><em>wayyōʾmᵉrû ṣārênû lōʾ yēḏᵉʿû wᵉlōʾ yirʾû ʿad ʾašer-nāḇôʾ ʾel-tôḵām</em>: 'and our enemies said, they will not know or see anything until we come among them and kill them and stop the work.' The enemies' strategy is a covert attack — enter undetected (<em>bôʾ ʾel-tôḵām</em> = come into their midst) and kill the workers before reinforcements can arrive. <em>wahăšiḇônû ʾet-hamᵉlāʾḵāh</em>: 'and cause the work to cease' — the ultimate goal is not territorial conquest but project termination. The psychological pressure is compounded by proximity: the workers' enemies were close enough to communicate their plans to allies inside Jerusalem.</p>",
    "12": "<p><em>wayhî kaʾašer bāʾû hayyᵉhûḏîm hayōšᵉḇîm ʾeṣlām wayyōʾmᵉrû lānû ʿeśer pᵉʿāmîm</em>: 'and it came about that the Jews who lived near them came and said to us ten times.' <em>ʿeśer pᵉʿāmîm</em> (ten times) is an idiom for repeated insistence (cf. Gen 31:7; Num 14:22; Job 19:3) — the warning was persistent and urgent. <em>mikkol-hamᵉqōmôt ʾašer-tāšûḇû ʿālênû</em>: the reading is difficult — possibly 'from all the places you will return to us' indicating the peripheral workers who returned from their home areas brought warnings about enemy movements.</p>",
    "13": "<p><em>waʾaʿămîḏ mittaḥtiyyôt lammāqôm mēʾaḥărê lahômāh batsᵉḥîḥîm waʾaʿămîḏ ʾet-hāʿām lᵉmišpāḥôt</em>: 'and I stationed people in the lower places behind the wall, in exposed places, and I stationed the people by their families.' The response is tactical: (1) strategic positioning at vulnerable points in the wall circuit; (2) organization by family units (<em>mišpāḥôt</em>) rather than by trade or district. Family cohesion as a military organizing principle was standard in ancient warfare — men fight harder for their families beside them. <em>ḥarbôtām rōmᵉḥêhem wᵉqaštôtām</em>: swords, spears, and bows — a fully equipped defense force.</p>",
    "14": "<p><em>wāʾeʾreh wāʾāqûm wāʾōmar ʾel-haḥōrîm wᵉʾel-hassᵉgānîm wᵉʾel-yeter hāʿām</em>: 'and I looked and rose and said to the nobles and the officials and the rest of the people.' Nehemiah's speech follows his tactical deployment. The address to all social levels — nobles, officials, people — reflects his characteristic unified-front approach. The exhortation: <em>ʾal-tîrᵉʾû mippᵉnêhem</em>, 'do not be afraid of them.' Then the motivating theology: <em>ʾet-YHWH haggāḏôl wᵉhannôrāʾ zikrû</em>, 'remember the great and awesome LORD.' The covenant formula <em>gāḏôl wᵉnôrāʾ</em> (great and awesome) from Nehemiah's own prayer (1:5) is now deployed as an exhortation to the workers. <em>wᵉhillaḥămû ʾal-ʾăḥêkem bᵉnêkem ûḇᵉnōtêkem nᵉšêkem ûḇāttêkem</em>: fight for brothers, sons, daughters, wives, and houses — the appeal is to family and home, the most primal motivations.</p>",
    "15": "<p><em>wayhî kaʾašer šāmᵉʿû ʾôyᵉḇênû kî-nôḏaʿ lānû wayyāp̄er hāʾĕlōhîm ʾet-ʿăṣātām</em>: 'and it came about that when our enemies heard that their plan was known to us, God frustrated their counsel.' <em>nôḏaʿ lānû</em>: 'it was known to us' — the intelligence leak or God's own disclosure disrupted the covert attack plan. <em>wayyāp̄er hāʾĕlōhîm ʾet-ʿăṣātām</em>: 'God frustrated their counsel' — <em>pārar</em> (to break, frustrate, annul) is the verb used for God breaking human plans (Ps 33:10; Prov 21:30). Nehemiah attributes the intelligence breakthrough directly to God. <em>wannāšāḇ kullānû ʾel-hahômāh</em>: 'and we all returned to the wall, each to his own work.' The return to work is itself an act of faith: the intelligence has been received, the threat assessed, God acknowledged — now back to building.</p>",
    "16": "<p><em>wayhî min-hayyôm hahûʾ ḥᵉṣî naʿărāy ʿōśîm bamᵉlāʾḵāh wᵉḥᵉṣyām maḥăzîqîm baḥănîtîm</em>: 'and from that day on, half of my servants worked on the construction, and half of them held the spears.' The dual workforce — half building, half defending — is Nehemiah's tactical adaptation to continuous threat. <em>wᵉhassinnôt wᵉhaqšātôt wᵉhašširyônôt wᵉhappᵉnîgîm</em>: 'the shields, bows, coats of mail, and commanders' — the full defensive apparatus. <em>Śārîm</em> (commanders) in v.16 are the officers who supervised the armed half while Nehemiah and the rebuilders directed the construction half.</p>",
    "17": "<p><em>hammāśôr babbinyān kāl-ʾeḥāḏ bᵉʾaḥat yāḏô ʿōśeh bamᵉlāʾḵāh wᵉʾaḥat maḥăzéqet haššālaḥ</em>: 'those who built the wall, each with one hand laboring on the work and with the other holding a weapon.' The image of the one-handed builder is one of the most vivid in the Hebrew Bible — a man simultaneously building and defending, unable to devote full attention to either but committed to both. <em>Hašālaḥ</em> (weapon, javelin) held in the defending hand while the building hand works. The verse has become an emblem of engaged ministry under pressure: the work continues despite threat; the threat does not stop the work.</p>",
    "18": "<p><em>wᵉhabbōnîm ʾîš ḥarbô ʾăzûrāh ʿal-motnāyw ûḇônîm</em>: 'and the builders, each with his sword girded at his side, and they built.' The sword (<em>ḥereb</em>) is <em>ʾăzûrāh ʿal-motnāyw</em>, 'bound at his loins' — the battle posture. Building and sword-wearing simultaneously expresses the paradox of the whole chapter. <em>wᵉhaššôpēr ʾeṣlî</em>: 'and the trumpeter was beside me' — Nehemiah himself had a dedicated trumpeter at his side. The <em>šôpār</em> (ram's horn trumpet) was the standard ancient Israelite signal instrument for military alerts (cf. Judg 3:27; 6:34; 1 Sam 13:3). Its proximity to Nehemiah meant the rally signal was always under his personal control.</p>",
    "19": "<p><em>wāʾōmar ʾel-haḥōrîm wᵉʾel-hassᵉgānîm wᵉʾel yeter hāʿām hammᵉlāʾḵāh rabbāh ûgᵉḏôlāh</em>: 'and I said to the nobles, the officials, and the rest of the people, the work is great and extensive.' The logistical challenge is acknowledged directly: the wall circuit was long, the workers spread out, the sections separated from each other. <em>waʾănaḥnû nip̄rāḏîm ʿal-hahômāh</em>: 'and we are separated from one another on the wall.' The dispersal of the workforce created communication gaps that made coordinated defense difficult — the trumpet system addressed exactly this problem.</p>",
    "20": "<p><em>bammāqôm ʾašer tišmᵉʿû ʾet-qôl haššôp̄ār šāmmāh tiqqābᵉṣû ʾēlênû</em>: 'wherever you hear the sound of the trumpet, rally to us there.' The trumpet as a communication system: one blast = gather to that point. <em>ʾĕlōhênû yillāḥem lānû</em>: 'our God will fight for us.' This is the holy-war formula distilled to its essence — five Hebrew words expressing the Deuteronomic conviction that YHWH fights Israel's battles (Deut 20:4; Exod 14:14). The formula transforms the defensive coordination from a merely military maneuver into a theological declaration: the defense of Jerusalem is YHWH's battle, and the workers are his instruments.</p>",
    "21": "<p><em>waʾănaḥnû ʿōśîm bamᵉlāʾḵāh waḥᵉṣyām maḥăzîqîm baḥănîtîm mēʿălôt haššaḥar ʿad ṣēʾt hakkôḵāḇîm</em>: 'and we did the work, with half holding the spears from the rise of dawn until the stars came out.' The working day is measured astronomically: from the first light (<em>ʿălôt haššaḥar</em> = the rising of the dawn) to the appearing of the stars (<em>ṣēʾt hakkôḵāḇîm</em>) — sunrise to full darkness, a maximum labor day. The extended hours reflect both the urgency of the project and the intensity of the threat: there was no safe time to reduce the guard.</p>",
    "22": "<p><em>gam bāʿēt hahîʾ āmartî lāʿām ʾîš wᵉnaʿărô yālînû bᵉṯôḵ yᵉrûšālaim</em>: 'also at that time I said to the people, let each man and his servant stay inside Jerusalem as a guard.' <em>yālîn</em> (overnight, spend the night) — rather than returning to their villages in the evening (standard practice for day-workers from surrounding towns), the workers were now to remain in Jerusalem overnight. This served two purposes: (1) the city was guarded through the night by the workforce, not just the permanent residents; (2) the workers were available for early morning resumption of work without travel time.</p>",
    "23": "<p><em>wᵉʾanî waʾaḥay waʾănāšay wᵉhaššōmᵉrîm ʾašer ʾaḥărāy ʾên-ʾănaḥnû p̄ōšᵉṭîm ḇᵉgāḏênû</em>: 'and I and my brothers and my servants and the men of the guard behind me — none of us removed our clothes.' The memoir concludes with the most personal detail: Nehemiah himself did not undress, even for sleep. <em>ʾîš šilḥô hammāyim</em>: the last phrase is textually difficult — possibly 'each had his weapon in his right hand' or 'each sent for water' (keeping his weapon even while fetching water). The final image is of relentless vigilance: the leader who set the tone of constant readiness lived it himself, clothes on, weapon in hand, maintaining the posture of alert service from first light to last star.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'nehemiah')
    merge_comm(c, ORIG)
    save_comm('mkt-original', 'nehemiah', c)
    total = sum(len(vs) for vs in ORIG.values())
    print(f'nehemiah mkt-original: {total} verses written (ch1-4)')

if __name__ == '__main__':
    main()
